def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            base = ratio ** 5 + (capacity % 5) * 3.7
            for a in range(1, int(capacity) + 3):
                if a % 3 == 0:
                    base += np.cbrt(ratio * a) / (a + epsilon)
                elif a % 2 == 0:
                    base -= np.sin(ratio * a / (capacity + 1))
                else:
                    base += np.log1p(ratio * a)
            if capacity % 4 == 3:
                base *= 1.25
            elif capacity % 4 == 2:
                base /= 1.1
            priority = base + np.sqrt(ratio) * 5
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log1p(capacity)
            for m in range(1, int(item) * 2):
                if m % 4 == 0:
                    priority += ((m ** 1.5) / (capacity + 1)) ** 1.2
                elif m % 3 == 0:
                    priority -= np.exp(-m / (item + epsilon))
                else:
                    priority += np.tanh(m / (item + epsilon))
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.sqrt(capacity + 1)
            factor = 1
            for n in range(1, int(item) + 2):
                factor *= (ratio + n / (capacity + 2))
                if factor > 10:
                    break
            priority *= factor * 1.1
            for x in range(1, int(capacity) + 1):
                if x % 5 == 0:
                    priority -= np.log(x + ratio + epsilon) * 0.4
                else:
                    priority += np.sin(ratio * x / (capacity + 1)) * 0.3
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * 1.5
            multiplier = 1
            for n in range(1, 7):
                multiplier *= (ratio + n / (capacity + 3))
                if multiplier > 7:
                    break
            for z in range(1, int(capacity/2) + 1):
                if z % 3 == 0:
                    priority += np.sqrt(z * ratio) / (z + epsilon)
                else:
                    priority -= (z ** 0.8) / (capacity + 1)
            priority *= multiplier
        elif 0.1 < ratio <= 0.5:
            total = 0.0
            for j in range(1, int(capacity) + 2):
                val = ((-1) ** j) * (ratio ** j) / (j + epsilon) * np.cos(j * ratio)
                total += val
            priority = abs(total) + 1.0
            if capacity % 2 == 0:
                priority *= 0.9
            else:
                priority *= 1.2
        else:
            acc = 0
            sign = 1
            for l in range(1, int(capacity) * 2):
                val = (ratio ** l) / (l + epsilon)
                acc += sign * val * np.log1p(l)
                sign = -sign
                if abs(acc) > 10:
                    break
            priority = abs(acc) + 0.75
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) * 2):
                if p % 3 == 0:
                    penalty += np.log(p + 2)
                elif p % 2 == 0:
                    penalty -= p * 0.15
                else:
                    penalty += np.sqrt(p)
            penalty = max(penalty, 0)
            priority += penalty
        if priority < 0:
            priority = abs(priority) * 1.05
        priorities[i] = priority
    return priorities
